var storage = multer.diskStorage({
  destination: function (req, file, cb) {
    cb(null, './public/uploads')
  },
  filename: function (req, file, cb) {
    cb(null, path.parse(file.originalname).name + '-' + Date.now() + path.extname(file.originalname));
  }
});

var upload = multer({ 
  storage: storage, 
  limits: { 
    fileSize: isInEnterpriseMode(req) ? Infinity : 1024 * 1024 * 5 // 5MB file size limit for non enterprise users 
  }, 
  fileFilter: function (req, file, cb) {
    var filetypes = /jpeg|jpg|png|gif|svg|pdf|doc|docx|zip/;
    var mimetype = filetypes.test(file.mimetype);
    var extname = filetypes.test(path.extname(file.originalname).toLowerCase());
    if (mimetype && extname) {
      return cb(null, true); 
    }
    cb("Only the following filetypes are allowed: jpeg, jpg, png, gif, svg, pdf, doc, docx, zip");
  } 
});

app.post('/upload', upload.single('file'), function (req, res, next) {
  if (req.file && ['.png', '.jpg', '.jpeg', '.svg'].includes(path.extname(req.file.filename))) {
    sharp(req.file.path).resize(200).toFile('./public/uploads/' + 'thumbnail-' + path.parse(req.file.filename).name + path.extname(req.file.filename));
  }
  res.send('Upload complete');
});

